arguments.file_text:
@page "/catalog"
@using sv_5290978bbd4445319aff854e1b8c3187.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="row g-0">
    @* Sidebar *@
    <div class="col-3">
        <ProductFilterPanel Categories="categories"
                            OnFiltersApplied="HandleFiltersApplied"
                            OnFiltersCleared="HandleFiltersCleared" />
    </div>

    @* Main content *@
    <div class="col-9 ps-4">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <span class="ms-3">Loading products…</span>
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label me-2 mb-0" for="sortSelect">Sort by:</label>
                    <select id="sortSelect" class="form-select form-select-sm d-inline-block w-auto"
                            value="@sortBy" @onchange="HandleSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted">
                    @if (searchResult is not null && searchResult.TotalCount > 0)
                    {
                        var first = (searchResult.Page - 1) * searchResult.PageSize + 1;
                        var last = Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount);
                        @($"Showing {first}–{last} of {searchResult.TotalCount} products")
                    }
                </span>
            </div>

            @* Product grid *@
            @if (searchResult is null || searchResult.Items.Count == 0)
            {
